// Author: abhinavkumarrath #include <bits/stdc++.h>using namespace std; #pragma GCC optimize("O3,unroll-loops")#pragma GCC target("avx2,bmi,bmi2,lzcnt,popcnt") using ll = long long;using vi = vector<int>;using vll = vector<ll>;using pii = pair<int, int>; #define pb push_back#define all(x) (x).begin(), (x).end()#define sz(x) (int)(x).size()#define fi first#define se second #define rep(i, a, b) for (int i = (a); i < (b); ++i)#define forn(i, n) rep(i, 0, n)#define per(i, a, b) for (int i = (b) - 1; i >= (a); --i)#define rofn(i, n) per(i, 0, n) template<class T> bool chmin(T& a, const T& b) { if (b < a) { a = b; return 1; } return 0; }template<class T> bool chmax(T& a, const T& b) { if (a < b) { a = b; return 1; } return 0; } void yes() { cout << "YES\n"; }void no() { cout << "NO\n"; } const int INF = 1e9;const ll LINF = 1e18; void solve() {    ll m, k;    cin >> m >> k;        vll p(m + 1), d(m + 1);    forn(i, m) cin >> p[i + 1];    forn(i, m) cin >> d[i + 1];        map<ll, vll> mpl, mpr;    map<ll, ll> traffic;        forn(i, m) {        traffic[p[i + 1]] = d[i + 1];        mpl[(d[i + 1] + p[i + 1]) % k].pb(p[i + 1]);        mpr[(((d[i + 1] - p[i + 1]) % k) + k) % k].pb(p[i + 1]);    }        for (auto& [val, vec] : mpl) sort(all(vec));    for (auto& [val, vec] : mpr) sort(all(vec));     auto get_next_left = [&](ll pos, ll t) -> ll {        ll val = (t + pos) % k;        if (!mpl.count(val)) return -1ll;        auto& vec = mpl[val];        auto it = lower_bound(all(vec), pos);        if (it == vec.begin()) return -1ll;        it--;        return *it;    };     auto get_next_right = [&](ll pos, ll t) -> ll {        ll val = (((t - pos) % k) + k) % k;        if (!mpr.count(val)) return -1ll;        auto& vec = mpr[val];        auto it = lower_bound(all(vec), pos + 1);        if (it == vec.end()) return -1ll;        return *it;    };     map<pair<ll, ll>, bool> dp;    int q;    cin >> q;        forn(i, q) {        ll x;        cin >> x;        ll dir = 1, t = 0;                set<pair<ll, ll>> states;        bool ok = false;                if (traffic.count(x) && traffic[x] == 0) dir ^= 1;                forn(it, 2 * m + 5) {            ll y = dir ? get_next_right(x, t) : get_next_left(x, t);            if (y == -1ll) {                ok = true;                break;            }                        t += abs(y - x);            x = y;            dir ^= 1;                        if (states.count({x, dir})) break;            states.insert({x, dir});                        if (dp.count({x, dir})) {                ok = dp[{x, dir}];                break;            }        }                for (auto state : states) {            dp[state] = ok;        }                if (ok) yes();        else no();    }} int main() {    ios_base::sync_with_stdio(false);    cin.tie(nullptr);        int t = 1;    cin >> t;    while (t--) {        solve();    }    return 0;}